  ('customs-7fec267e-moex-00096', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '在其他條件不變下，一國貨幣貶值：', '["有利於該國的對外直接投資", "有利於該國國民出國旅遊", "有利於該國的出口", "有利於該國的進口"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00097', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '有關國內生產毛額（grossdomesticproduct,GDP），下列敘述何者錯誤？', '["國內生產毛額原則上是加總一國境內所生產出不同類型最終商品與勞務的市場價值（market value）， 但對於沒有市場交易的最終商品與勞務，則以取得該最終商品與勞務成本來加總計入", "一國境內所新生產的資本財（capitalgood）不能計入其國內生產毛額之中", "為降低基期選擇對實質國內生產毛額的影響，美國經濟分析局（U.S.BureauofEconomicAnalysis）採用 連鎖加權實質國內生產毛額（chain-weightedrealGDP）來衡量", "國內生產毛額並不能良好地衡量一國的經濟福祉（economic welfare），因為國內生產毛額無法反映所 得分配問題和環境品質、沒有計入休閒價值、忽略商品與勞務的品質變化等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00098', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '如果新臺幣兌美元貶值且預期未來新臺幣兌美元匯率未變，在其他條件不變下，則現在進場購買美元資產 的預期新臺幣利潤會：', '["減少", "增加", "不變", "增加、減少或不變皆有可能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00099', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '某一經濟體系其消費函數為CC c(YT)，課稅TT tY。此經濟體系的邊際消費傾向與平均消費傾', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00100', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '0 向分別為： C cT C cT', '["c(1t)；c(1t)+ 0 0", "c；c+ 0 0 Y YT C C", "c(1t)；c(1t)+ 0", "c；c+ 0 Y YT"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing"], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00101', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列何者不具有自動穩定因子（automaticstabilizer）的功能？', '["企業的保留盈餘", "累進所得稅", "失業保險制度", "乘數－加速原理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00102', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列何種因素不會使總合供給線移動？', '["人口老化", "貨幣供給增加", "教育水準提高", "基本工資大幅調漲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00103', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '停滯性膨脹（stagflation）通常是因為下列何種變動而產生？', '["總合需求曲線右移", "總合需求曲線左移", "總合供給曲線右移", "總合供給曲線左移"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00104', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設一國經濟原先處在長期均衡狀態下，根據總合供給與總合需求模型，在其他條件不變下，當其政府恆 常性調降對家戶所課徵的定額稅時：', '["長短期均衡名目GDP都會增加", "長短期均衡名目GDP都會減少", "短期均衡名目GDP會增加且長期均衡名目GDP不變", "短期均衡名目GDP會減少且長期均衡名目GDP會增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00105', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '若美國、日本等大國實施擴張性財政政策，在資金自由移動下，對採行浮動匯率制度之小國的淨出口餘額將：', '["上升", "下降", "不變", "題意資訊不足，無法判斷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
